3	#include <deep_ep/common/compiled.cuh>
4	#include <deep_ep/common/layout.cuh>
5	#include <deep_ep/common/math.cuh>
6	#include <deep_ep/common/ptx.cuh>
7	
8	
9	namespace deep_ep::elastic {
10	
11	template <bool kDoExpand, bool kCachedMode, bool kDoZeroPadding,
12	          // NOTES: this channel concept only applies for scale-out ranks
13	          int kNumSMs, int kNumChannels, int kNumWarps,
14	          int kNumScaleoutRanks, int kNumScaleupRanks,
15	          int kNumHiddenBytes, int kNumSFPacks,
16	          int kNumMaxTokensPerRank,
17	          int kNumExperts, int kNumTopk, int kExpertAlignment,
18	          int kNumRanks = kNumScaleoutRanks * kNumScaleupRanks,
19	          int kNumThreads = kNumWarps * 32,
20	          int kNumMaxTokensPerChannel = math::constexpr_ceil_div(kNumMaxTokensPerRank, kNumChannels),
21	          bool kDoCreateLinkedList = (kNumScaleoutRanks > 1 and not kCachedMode)>
22	__global__ void __launch_bounds__(kNumThreads, 1)
23	dispatch_copy_epilogue_impl(void* buffer, void* workspace,
24	                            int* psum_num_recv_tokens_per_scaleup_rank,
25	                            int* psum_num_recv_tokens_per_expert,
26	                            void* recv_x, sf_pack_t* recv_sf,
27	                            topk_idx_t* recv_topk_idx, float* recv_topk_weights,
28	                            int* recv_src_metadata,
29	                            int* channel_linked_list,
30	                            int* num_unaligned_recv_tokens_per_expert,
31	                            int num_recv_tokens,
32	                            const int recv_sf_token_stride, const int recv_sf_hidden_stride,
33	                            const int scaleout_rank_idx, const int scaleup_rank_idx) {
34	    // Utils
35	    const auto sm_idx = static_cast<int>(blockIdx.x), thread_idx = static_cast<int>(threadIdx.x);
36	    const auto warp_idx = ptx::get_warp_idx(), lane_idx = ptx::get_lane_idx();
37	    const auto global_warp_idx = warp_idx * kNumSMs + sm_idx;
38	
39	    // For top-k index transformations
40	    constexpr int kNumExpertsPerRank = kNumExperts / kNumRanks;
41	    const auto rank_idx = scaleout_rank_idx * kNumScaleupRanks + scaleup_rank_idx;
42	    const auto expert_start_idx = kNumExpertsPerRank * rank_idx, expert_end_idx = kNumExpertsPerRank * (rank_idx + 1);
43	
44	    // Buffer layouts
45	    extern __shared__ __align__(ptx::kNumTMAAlignBytes) int8_t smem[];
46	    const auto token_layout = layout::TokenLayout(kNumHiddenBytes, kNumSFPacks * sizeof(sf_pack_t), kNumTopk, true);
47	    const auto tma_buffer = layout::BufferLayout<true>(token_layout, kNumWarps, 1, smem)
48	        .get_rank_buffer(warp_idx).get_token_buffer(0);
49	    const auto scaleup_buffer = layout::BufferLayout<false>(token_layout, kNumScaleupRanks, kNumScaleoutRanks * kNumMaxTokensPerRank, buffer);
50	
51	    // Init TMA
52	    ptx::arrival_phase phase = 0;
53	    const auto mbarrier_ptr = tma_buffer.get_mbarrier_ptr();
54	    if (ptx::elect_one_sync())
55	        ptx::mbarrier_init_with_fence(mbarrier_ptr, 1);
56	    __syncwarp();
57	
58	    // Will block until the main dispatch kernel has finished and all data are visible
59	    // NOTES: PDL is used, please do not use `__ldg`
60	    cudaGridDependencySynchronize();
61	
62	    // For no CPU sync case, the number of received tokens should be read from the GPU tensor
63	    if (num_recv_tokens == kNumMaxTokensPerRank * kNumRanks)
64	        num_recv_tokens = psum_num_recv_tokens_per_scaleup_rank[kNumScaleupRanks - 1];
65	
66	    // Current rank indices should be maintained
67	    int current_rank_idx = -1, stored_psum_num_recv_tokens;
68	    int current_rank_start = 0, current_rank_end = 0;
69	    #pragma unroll
70	    for (int i = global_warp_idx; i < num_recv_tokens; i += kNumWarps * kNumSMs) {
71	        // Calculate token index in the buffer
72	        while (i >= current_rank_end) {
73	            current_rank_idx += 1;
74	            EP_DEVICE_ASSERT(current_rank_idx < kNumScaleupRanks);
75	            const auto stored_lane_idx = current_rank_idx % 32;
76	            if (stored_lane_idx == 0 and current_rank_idx + lane_idx < kNumScaleupRanks)
77	                stored_psum_num_recv_tokens = psum_num_recv_tokens_per_scaleup_rank[current_rank_idx + lane_idx];
78	            current_rank_start = current_rank_end;
79	            current_rank_end = ptx::exchange(stored_psum_num_recv_tokens, stored_lane_idx);
80	        }
81	        const auto buffer_token = scaleup_buffer.get_rank_buffer(current_rank_idx).get_token_buffer(i - current_rank_start);
82	
83	        // Wait buffer releases
84	        ptx::tma_store_wait();
85	        __syncwarp();
86	
87	        // Issue TMA loads
88	        // Including all stuffs: data, SF, top-k metadata
89	        if (ptx::elect_one_sync()) {
90	            ptx::tma_load_1d(tma_buffer.get_base_ptr(), buffer_token.get_base_ptr(),
91	                             mbarrier_ptr, tma_buffer.get_num_bytes<false>());
92	            ptx::mbarrier_arrive_and_set_tx(mbarrier_ptr, tma_buffer.get_num_bytes<false>());
93	        }
94	        __syncwarp();
95	
96	        // Load target expert indices separately to tolerate TMA load latency
97	        EP_STATIC_ASSERT(kNumTopk <= 32, "Too many top-k selections");
98	        int dst_expert_idx = -1;
99	        if (lane_idx < kNumTopk)
100	            dst_expert_idx = buffer_token.get_topk_idx_ptr()[lane_idx];
101	        __syncwarp();
102	
103	        // Validate target expert indices and store for non-expand mode
104	        const auto in_range = expert_start_idx <= dst_expert_idx and dst_expert_idx < expert_end_idx;
105	        const auto master_src_topk_idx = ptx::get_master_lane_idx(ptx::gather(in_range));
106	        dst_expert_idx = in_range ? dst_expert_idx - expert_start_idx : -1;
107	        EP_DEVICE_ASSERT(ptx::deduplicate(dst_expert_idx, lane_idx) or dst_expert_idx == -1);
108	        if (not kDoExpand and lane_idx < kNumTopk)
109	            recv_topk_idx[i * kNumTopk + lane_idx] = static_cast<topk_idx_t>(dst_expert_idx);
110	        __syncwarp();
111	
112	        // Calculate target indices in the tensor
113	        constexpr int kMetadataStride = 2 + kNumTopk;
114	        int dst_tensor_idx = -1;
115	        if (not kDoExpand and ptx::elect_one_sync()) {
116	            dst_tensor_idx = i;
117	        } else if (kDoExpand and kCachedMode and lane_idx < kNumTopk) {
118	            // Cached expand mode: read pre-computed dst_tensor_idx from metadata
119	            dst_tensor_idx = recv_src_metadata[i * kMetadataStride + 2 + lane_idx];
120	        } else if (kDoExpand and not kCachedMode and dst_expert_idx >= 0) {
121	            dst_tensor_idx = atomicAdd(psum_num_recv_tokens_per_expert + dst_expert_idx, 1);
122	        }
123	        __syncwarp();
124	
125	        // Wait for TMA arrival
126	        if (ptx::elect_one_sync())
127	            ptx::mbarrier_wait_and_flip_phase(mbarrier_ptr, phase);
128	        __syncwarp();
129	
130	        // Maintain linked list
131	        if constexpr (kDoCreateLinkedList) {
132	            if (ptx::elect_one_sync())
133	                channel_linked_list[tma_buffer.get_linked_list_idx_ptr()[master_src_topk_idx]] = i;
134	            __syncwarp();
135	        }
136	
137	        // Issue TMA stores for data
138	        if (kDoExpand ? (dst_tensor_idx >= 0) : ptx::elect_one_sync()) {
139	            ptx::tma_store_1d(math::advance_ptr(recv_x, static_cast<int64_t>(dst_tensor_idx) * kNumHiddenBytes),
140	                              tma_buffer.get_hidden_ptr(), kNumHiddenBytes);
141	            ptx::tma_store_commit();
142	        }
143	        __syncwarp();
144	
145	        // Store SF
146	        if constexpr (kNumSFPacks > 0) {
147	            constexpr auto kNumFullIters = kNumSFPacks / 32;
148	            const bool do_last_iter = (kNumSFPacks % 32 != 0) and (kNumFullIters * 32 + lane_idx < kNumSFPacks);
149	            EP_STATIC_ASSERT(sizeof(sf_pack_t) % 4 == 0, "Unaligned SF element type");
150	
151	            // Load into registers
152	            const auto smem_src_ptr = tma_buffer.get_sf_ptr();
153	            sf_pack_t reg_src[kNumFullIters + 1];
154	            #pragma unroll
155	            for (int k = 0; k < kNumFullIters; ++ k)
156	                reg_src[k] = smem_src_ptr[k * 32 + lane_idx];
157	            if (do_last_iter)
158	                reg_src[kNumFullIters] = smem_src_ptr[kNumFullIters * 32 + lane_idx];
159	
160	            // Prepare strides
161	            const auto recv_sf_token_stride_i64 = static_cast<int64_t>(recv_sf_token_stride);
162	            const auto recv_sf_hidden_stride_i64 = static_cast<int64_t>(recv_sf_hidden_stride);
163	
164	            // Iterate through all valid indices and store into output buffer
165	            auto mask = kDoExpand ? ptx::gather(dst_tensor_idx >= 0) : 1;
166	            while (mask) {
167	                const int valid_lane_idx = __ffs(mask) - 1;
168	                const auto gmem_dst = math::advance_ptr<sf_pack_t>(recv_sf,
169	                    ptx::exchange(dst_tensor_idx, valid_lane_idx) * (recv_sf_token_stride_i64 * sizeof(sf_pack_t)));
170	                #pragma unroll
171	                for (int k = 0; k < kNumFullIters; ++ k)
172	                    gmem_dst[(k * 32 + lane_idx) * recv_sf_hidden_stride_i64] = reg_src[k];
173	                if (do_last_iter)
174	                    gmem_dst[(kNumFullIters * 32 + lane_idx) * recv_sf_hidden_stride_i64] = reg_src[kNumFullIters];
175	                mask ^= 1 << valid_lane_idx;
176	            }
177	        }
178	
179	        // Store the top-k weights
180	        if (kDoExpand and recv_topk_weights != nullptr and dst_tensor_idx >= 0) {
181	            recv_topk_weights[dst_tensor_idx] = tma_buffer.get_topk_weights_ptr()[lane_idx];
182	        } else if (not kDoExpand and recv_topk_weights != nullptr and lane_idx < kNumTopk) {
183	            // For backward, weights are optional
184	            recv_topk_weights[i * kNumTopk + lane_idx] = tma_buffer.get_topk_weights_ptr()[lane_idx];
185	        }
186	        __syncwarp();
187	
188	        // Write source token index (skip in cached mode as metadata is reused)
189	        // And:
190	        //   - Non-hybrid mode: the source scaleup peer rank index and master top-k lane index
191	        //   - Hybrid mode: the slot index and master top-k lane index
192	        if constexpr (not kCachedMode) {
193	            if (ptx::elect_one_sync()) {
194	                recv_src_metadata[i * kMetadataStride + 0] = *tma_buffer.get_src_token_global_idx_ptr();
195	                if constexpr (kNumScaleoutRanks == 1) {
196	                    recv_src_metadata[i * kMetadataStride + 1] = current_rank_idx * kNumTopk + master_src_topk_idx;
197	                } else {
198	                    recv_src_metadata[i * kMetadataStride + 1] = (i - current_rank_start) * kNumTopk + master_src_topk_idx;
199	                }
200	            }
201	            __syncwarp();
202	
203	            // Write reduction source indices
204	            if (kDoExpand and lane_idx < kNumTopk)
205	                recv_src_metadata[i * kMetadataStride + 2 + lane_idx] = dst_tensor_idx;
206	            __syncwarp();
207	        }
208	    }
209	
210	    // Maintain linked list's ending
211	    // Or you can understand it as writing the tail at once
212	    if constexpr (kDoCreateLinkedList) {
213	        constexpr int kNumScaleupRanksPerLane = math::constexpr_ceil_div(kNumScaleupRanks, 32);
214	        const auto workspace_layout = layout::WorkspaceLayout(workspace, kNumScaleoutRanks, kNumScaleupRanks, kNumExperts);
215	        for (int i = global_warp_idx; i < kNumChannels; i += kNumSMs * kNumWarps) {
216	            #pragma unroll
217	            for (int j = 0; j < kNumScaleupRanksPerLane; ++ j) {
218	                if (const auto k = j * 32 + lane_idx; j < (kNumScaleupRanksPerLane - 1) or k < kNumScaleupRanks) {
219	                    channel_linked_list[
220	                        *workspace_layout.get_channel_scaleup_tail_ptr(i, k)
221	                    ] = -1;
222	
223	                    // Clean for combine usages
224	                    *workspace_layout.get_channel_scaleup_tail_ptr(i, k) = 0;
225	                }
226	            }
227	            __syncwarp();
228	        }
229	    }
230	
231	    // Zero padding: clear the alignment gaps between experts in the expanded output
232	    if constexpr (kDoZeroPadding and kDoExpand) {
233	        // Wait for last TMA store from main loop to complete
234	        ptx::tma_store_wait();
235	        __syncwarp();
236	
237	        // Zero out the TMA buffer's hidden region in smem
238	        if (ptx::elect_one_sync())
239	            ptx::st_bulk<kNumHiddenBytes>(tma_buffer.get_hidden_ptr());
240	        __syncwarp();
241	
242	        // Read all expert unaligned counts in parallel
243	        constexpr int kNumExpertsPerLane = math::constexpr_ceil_div(kNumExpertsPerRank, 32);
244	        int num_experts_per_lane[kNumExpertsPerLane];
245	        #pragma unroll
246	        for (int i = 0; i < kNumExpertsPerLane; ++ i) {
247	            const int expert_idx = i * 32 + lane_idx;
248	            num_experts_per_lane[i] = expert_idx < kNumExpertsPerRank ?
249	                num_unaligned_recv_tokens_per_expert[expert_idx] : 0;
250	        }
251	
252	        // Single while loop over all padding tokens
253	        int wave_idx = 0, wave_pad_psum = 0, wave_tensor_psum = 0, pad_idx = global_warp_idx;
254	        while (true) {
255	            // Jump into the right position
256	            int dst_tensor_idx;
257	            while (wave_idx < kNumExpertsPerLane) {
258	                // Assign current wave expert token count
259	                int wave_num_experts_per_lane;
260	                #pragma unroll
261	                for (int i = 0; i < kNumExpertsPerLane; ++ i)
262	                    wave_num_experts_per_lane = i == wave_idx ? num_experts_per_lane[i] : wave_num_experts_per_lane;
263	                int wave_num_pads_per_lane = 0;
264	                if (wave_idx * 32 + lane_idx < kNumExpertsPerRank) {
265	                    wave_num_pads_per_lane = kExpertAlignment - (wave_num_experts_per_lane % kExpertAlignment);
266	                    wave_num_pads_per_lane = wave_num_pads_per_lane == kExpertAlignment ? 0 : wave_num_pads_per_lane;
267	                }
268	                int wave_num_pads = ptx::reduce_add(wave_num_pads_per_lane);
269	
270	                // Check whether hit the current wave
271	                if (pad_idx < wave_pad_psum + wave_num_pads) {
272	                    const int local_pad_idx = pad_idx - wave_pad_psum;
273	                    const int pad_psum = ptx::warp_inclusive_sum(wave_num_pads_per_lane, lane_idx);
274	                    const int owner_lane_idx = __ffs(__ballot_sync(0xffffffff, pad_psum > local_pad_idx)) - 1;
275	                    dst_tensor_idx = wave_tensor_psum + ptx::exchange(
276	                        ptx::warp_exclusive_sum(wave_num_experts_per_lane + wave_num_pads_per_lane, lane_idx) +
277	                        wave_num_experts_per_lane + local_pad_idx - (pad_psum - wave_num_pads_per_lane),
278	                        owner_lane_idx);
279	                    break;
280	                }
281	
282	                // Move to the next wave
283	                wave_idx ++;
284	                wave_pad_psum += wave_num_pads;
285	                wave_tensor_psum += ptx::reduce_add(wave_num_experts_per_lane + wave_num_pads_per_lane);
286	            }
287	            if (wave_idx >= kNumExpertsPerLane)
288	                break;
289	
290	            // Zero data via TMA store
291	            if (ptx::elect_one_sync()) {
292	                ptx::tma_store_1d(math::advance_ptr(recv_x, static_cast<int64_t>(dst_tensor_idx) * kNumHiddenBytes),
293	                                  tma_buffer.get_hidden_ptr(), kNumHiddenBytes);
294	                ptx::tma_store_commit();
295	            }
296	            __syncwarp();
297	
298	            // Zero weights
299	            if (recv_topk_weights != nullptr and ptx::elect_one_sync())
300	                recv_topk_weights[dst_tensor_idx] = 0.0f;
301	            __syncwarp();
302	
303	            // Zero SF
304	            if constexpr (kNumSFPacks > 0) {
305	                const auto recv_sf_token_stride_i64 = static_cast<int64_t>(recv_sf_token_stride);
306	                const auto recv_sf_hidden_stride_i64 = static_cast<int64_t>(recv_sf_hidden_stride);
307	                constexpr sf_pack_t zero_sf_pack = {0};
308	                const auto gmem_dst = math::advance_ptr<sf_pack_t>(recv_sf,
309	                    dst_tensor_idx * (recv_sf_token_stride_i64 * sizeof(sf_pack_t)));
310	                constexpr auto kNumFullIters = kNumSFPacks / 32;
311	                #pragma unroll
312	                for (int k = 0; k < kNumFullIters; ++ k)
313	                    gmem_dst[(k * 32 + lane_idx) * recv_sf_hidden_stride_i64] = zero_sf_pack;
314	                if constexpr (kNumSFPacks % 32 != 0) {
315	                    if (kNumFullIters * 32 + lane_idx < kNumSFPacks)
316	                        gmem_dst[(kNumFullIters * 32 + lane_idx) * recv_sf_hidden_stride_i64] = zero_sf_pack;
317	                }
318	            }
319	            __syncwarp();
320	
321	            // Try to fill the next one
322	            pad_idx += kNumSMs * kNumWarps;
323	        }
324	    }
325	}
326	
327	}  // namespace deep_ep::elastic
