136	static layout::TokenLayout get_dispatch_token_layout(
137	    const int& hidden, const int& elem_size, const int& num_sf_packs, const int& num_topk) {
138	    return layout::TokenLayout(hidden * elem_size, num_sf_packs * sizeof(sf_pack_t), num_topk, true);
