152	    void destroy() {
153	        EP_HOST_ASSERT(not destroyed);
154	
155	        // Finish all works on all GPUs
156	        barrier(true, true);
157	
158	        // Deallocate host workspaces
159	        CUDA_RUNTIME_CHECK(cudaFreeHost(host_workspace));
160	
161	        // Destroy NCCL context
162	        nccl_context->finalize();
163	
164	        // Cannot use anymore
165	        destroyed = true;
166	    }
