210	    void engram_write(const torch::Tensor& storage, const std::optional<torch::Tensor>& sf) {
211	        // Ensure previous fetch are finished
212	        barrier(false, true);
213	
214	        const auto compute_stream = at::cuda::getCurrentCUDAStream();
215	
216	        // Check storage
217	        const auto [num_entries, hidden] = get_shape<2>(storage);
218	        EP_HOST_ASSERT(storage.scalar_type() == torch::kBFloat16 or
219	                       storage.scalar_type() == torch::kFloat8_e4m3fn);
220	        EP_HOST_ASSERT(storage.is_cuda() and storage.is_contiguous());
221	        num_engram_entries = num_entries, engram_hidden = hidden;
222	
223	        // Store globally-replicated FP8 scaling factors for local gather during fetch.
224	        if (sf.has_value())
225	            EP_HOST_ASSERT(sf->dim() == 2 and sf->is_cuda() and sf->is_contiguous() and
226	                           sf->element_size() == sizeof(sf_pack_t));
227	        engram_sf = sf;
228	
229	        // Write storage to CPU segment at back of buffer
230	        EP_HOST_ASSERT(storage.nbytes() <= num_cpu_buffer_bytes and "Engram storage exceeds CPU buffer size");
231	        const auto cpu_write_offset = allow_hybrid_mode
232	            ? static_cast<int64_t>(nccl_context->scaleup_rank_idx) * num_cpu_buffer_bytes : 0;
233	        CUDA_RUNTIME_CHECK(cudaMemcpyAsync(
234	            math::advance_ptr(buffer, num_gpu_buffer_bytes + cpu_write_offset),
235	            storage.data_ptr(), storage.nbytes(),
236	            cudaMemcpyDeviceToDevice, compute_stream));
237	
238	        // Ensure data is visible for all ranks
239	        barrier(false, true);
240	    }
