377	    void agrs_set_config(const int64_t& num_max_session_bytes,
378	                         const int& new_num_max_agrs_per_session) {
379	        // Flush previous operations
380	        barrier(true, true);
381	
382	        EP_HOST_ASSERT(nccl_context->num_ranks > 1);
383	        EP_HOST_ASSERT(num_max_session_bytes > 0 and new_num_max_agrs_per_session > 0);
384	        EP_HOST_ASSERT(num_max_session_bytes <= num_buffer_bytes);
385	        EP_HOST_ASSERT(new_num_max_agrs_per_session <= layout::WorkspaceLayout::kNumMaxInflightAGRS);
386	        EP_HOST_ASSERT(nccl_context->num_nvl_ranks == nccl_context->num_ranks);
387	        this->num_max_agrs_session_bytes = math::align<int64_t>(num_max_session_bytes, 32);
388	        this->num_max_agrs_per_session = new_num_max_agrs_per_session;
