586	    static int64_t get_dispatch_buffer_size(const int& num_max_tokens_per_rank,
587	                                            const int& hidden, const int& num_sf_packs, const int& num_topk,
588	                                            const int& elem_size,
589	                                            const int& num_scaleout_ranks, const int& num_scaleup_ranks,
590	                                            const bool& is_scaleup_nvlink) {
591	        const auto num_ranks = num_scaleup_ranks * num_scaleout_ranks;
592	        const auto token_layout = get_dispatch_token_layout(hidden, elem_size, num_sf_packs, num_topk);
593	
594	        if (num_scaleout_ranks == 1) {
595	            // Direct dispatch
596	            const auto send_buffer_layout = layout::BufferLayout<false>(
597	                token_layout, is_scaleup_nvlink ? 0 : 1, num_max_tokens_per_rank);
598	            const auto recv_buffer_layout = layout::BufferLayout<false>(
599	                token_layout, num_ranks, num_max_tokens_per_rank);
600	            return send_buffer_layout.get_num_bytes() + recv_buffer_layout.get_num_bytes();
601	        } else {
602	            // Hybrid dispatch
603	            const auto scaleup_recv_buffer = layout::BufferLayout<false>(
604	                token_layout, num_scaleup_ranks, num_scaleout_ranks * num_max_tokens_per_rank);
605	            const auto scaleout_send_buffer = layout::BufferLayout<false>(
606	                token_layout, 1, num_max_tokens_per_rank);
607	            const auto scaleout_recv_buffer = layout::BufferLayout<false>(
608	                token_layout, num_scaleout_ranks,
609	                /* kNumChannels * kNumMaxTokensPerChannel */ num_max_tokens_per_rank + kNumMaxChannels);
610	            return scaleup_recv_buffer.get_num_bytes() +
611	                   scaleout_send_buffer.get_num_bytes() +
612	                   scaleout_recv_buffer.get_num_bytes();
613	        }
614	    }
615	
616	    static int64_t get_combine_buffer_size(const int& num_max_tokens_per_rank, const int& hidden, const int& num_topk,
617	                                           const int& num_scaleout_ranks, const int& num_scaleup_ranks,
618	                                           const bool& is_scaleup_nvlink,
619	                                           const bool& allow_multiple_reduction) {
620	        const auto num_ranks = num_scaleup_ranks * num_scaleout_ranks;
621	        const auto token_layout = get_combine_token_layout(hidden, sizeof(nv_bfloat16), num_topk);
622	
623	        if (num_scaleout_ranks == 1) {
624	            // Direct combine
625	            const auto num_tokens_in_layout = allow_multiple_reduction ? std::min(num_ranks, num_topk) : num_topk;
626	            const auto send_buffer_layout = layout::BufferLayout<false>(
627	                token_layout, is_scaleup_nvlink ? 0 : num_ranks,
628	                // For single reduction cases, the maximum number of received tokens is
629	                // `num_ranks * num_topk * num_max_tokens_per_rank` (we assume the bad case of `do_expand=True`)
630	                num_max_tokens_per_rank * (allow_multiple_reduction ? 1 : num_topk));
631	            const auto recv_buffer_layout = layout::BufferLayout<false>(
632	                token_layout, num_tokens_in_layout, num_max_tokens_per_rank);
633	            return send_buffer_layout.get_num_bytes() + recv_buffer_layout.get_num_bytes();
634	        } else {
635	            // Hybrid combine
636	            const int num_tokens_in_scaleup_layout = allow_multiple_reduction ? std::min(num_scaleup_ranks, num_topk) : num_topk;
637	            const int num_tokens_in_scaleout_layout = allow_multiple_reduction ? std::min(num_scaleout_ranks, num_topk) : num_topk;
638	            const auto scaleup_recv_buffer = layout::BufferLayout<false>(
639	                token_layout, num_tokens_in_scaleup_layout, num_scaleout_ranks * num_max_tokens_per_rank);
640	            const auto scaleout_recv_buffer = layout::BufferLayout<false>(
641	                token_layout, num_tokens_in_scaleout_layout, num_max_tokens_per_rank);
642	            const auto scaleout_send_buffer = layout::BufferLayout<false>(
643	                token_layout, allow_multiple_reduction ? 1 : num_topk,
644	                /* kNumChannels * num_scaleout_ranks * kNumMaxTokensPerChannel */
645	                num_scaleout_ranks * (num_max_tokens_per_rank + kNumMaxChannels));
646	            return scaleup_recv_buffer.get_num_bytes() +
647	                   scaleout_send_buffer.get_num_bytes() +
648	                   scaleout_recv_buffer.get_num_bytes();
649	        }
650	    }
651	
652	    static int64_t calculate_buffer_size(const int64_t& nccl_comm,
653	                                         const int& num_max_tokens_per_rank, const int& hidden,
654	                                         int num_topk, const bool& use_fp8_dispatch,
655	                                         const bool& allow_hybrid_mode,
656	                                         const bool& allow_multiple_reduction) {
657	        EP_HOST_ASSERT(num_max_tokens_per_rank > 0 and hidden > 0);
658	
659	        // The worst case SF bytes must be less than the main part
660	        EP_HOST_ASSERT(math::ceil_div(hidden, 32) * sizeof(float) <= hidden);
661	
662	        // NOTES: there are lots of `kNumTopk <= 32` restrictions, so we use 32 to calculate token size
663	        num_topk = num_topk == 0 ? 32 : num_topk;
664	
665	        // Topology
666	        const auto [num_rdma_ranks, num_nvl_ranks] = nccl::get_physical_domain_size(nccl_comm);
667	        const auto [num_scaleout_ranks, num_scaleup_ranks] = nccl::get_logical_domain_size(nccl_comm, allow_hybrid_mode);
668	        const auto is_scaleup_nvlink = num_scaleup_ranks == num_nvl_ranks;
669	
670	        // Dispatch size
671	        const auto elem_size = use_fp8_dispatch ? sizeof(__nv_fp8_e4m3) : sizeof(nv_bfloat16);
672	        const auto num_sf_packs = use_fp8_dispatch ? math::ceil_div(hidden, 32) : 0; // An approximation for number of SF packs
673	        const auto num_dispatch_bytes = get_dispatch_buffer_size(
674	            num_max_tokens_per_rank, hidden, num_sf_packs, num_topk, elem_size,
675	            num_scaleout_ranks, num_scaleup_ranks,
676	            is_scaleup_nvlink);
677	
678	        // Combine layout
679	        const auto num_combine_bytes = get_combine_buffer_size(
680	            num_max_tokens_per_rank, hidden, num_topk,
681	            num_scaleout_ranks, num_scaleup_ranks,
682	            is_scaleup_nvlink, allow_multiple_reduction);
683	
684	        // Return the maximum of those layouts, aligned to 2 MB
685	        return math::align(std::max(num_dispatch_bytes, num_combine_bytes), symmetric::kNumAlignmentBytes);
686	    }
687	
688	    static symmetric::cpu_handle_t create_cpu_handle(const int64_t& num_cpu_bytes) {
689	        EP_HOST_ASSERT(num_cpu_bytes > 0 and num_cpu_bytes % symmetric::kNumAlignmentBytes == 0);
690	        return symmetric::HybridElasticSymmetricMemory::create_cpu_handle(num_cpu_bytes);
691	    }
692	
693	    std::tuple<torch::Tensor, std::optional<torch::Tensor>,
694	               std::optional<torch::Tensor>, std::optional<torch::Tensor>,
695	               std::optional<torch::Tensor>,
696	               int, int,
697	               std::vector<int>,
698	               torch::Tensor, torch::Tensor, torch::Tensor,
699	               torch::Tensor, torch::Tensor,
700	               std::optional<torch::Tensor>, std::optional<torch::Tensor>,
701	               std::optional<EventHandle>>
702	    dispatch(const torch::Tensor& x,
703	             const std::optional<torch::Tensor>& sf,
704	             const torch::Tensor& topk_idx,
705	             const std::optional<torch::Tensor>& topk_weights,
706	             const std::optional<torch::Tensor>& cumulative_local_expert_recv_stats,
707	             const std::optional<int>& cached_num_recv_tokens,
708	             const std::optional<int>& cached_num_expanded_tokens,
709	             const std::optional<std::vector<int>>& cached_num_recv_tokens_per_expert_list,
710	             const std::optional<torch::Tensor>& cached_psum_num_recv_tokens_per_scaleup_rank,
711	             const std::optional<torch::Tensor>& cached_psum_num_recv_tokens_per_expert,
712	             const std::optional<torch::Tensor>& cached_num_unaligned_recv_tokens_per_expert,
713	             const std::optional<torch::Tensor>& cached_dst_buffer_slot_idx,
714	             const std::optional<torch::Tensor>& cached_token_metadata_at_forward,
715	             const std::optional<torch::Tensor>& cached_recv_src_metadata,
716	             const std::optional<torch::Tensor>& cached_channel_linked_list,
717	             const int& num_max_tokens_per_rank,
718	             const int& num_experts, const int& expert_alignment,
719	             const int& num_sms, const int& num_qps,
720	             const std::optional<EventHandle>& previous_event,
721	             const std::optional<EventHandle>& previous_event_before_epilogue,
722	             const bool& async_with_compute_stream,
723	             const bool& allocate_on_comm_stream,
724	             const bool& do_handle_copy, const bool& do_cpu_sync,
725	             const bool& do_expand, const bool& do_zero_padding,
726	             const bool& use_tma_aligned_col_major_sf) const {
727	        // Check SM count
728	        EP_HOST_ASSERT(num_sms > 0);
729	
730	        // Zero padding only makes sense with expand mode
731	        EP_HOST_ASSERT(not do_zero_padding or do_expand);
732	
733	        // Cached mode must have responding handles
734	        const bool cached_mode = cached_num_recv_tokens.has_value();
735	        if (cached_mode) {
736	            EP_HOST_ASSERT(cached_num_recv_tokens.has_value());
737	            EP_HOST_ASSERT(cached_num_recv_tokens_per_expert_list.has_value());
738	            EP_HOST_ASSERT(cached_num_expanded_tokens.has_value());
739	            EP_HOST_ASSERT(cached_psum_num_recv_tokens_per_scaleup_rank.has_value());
740	            EP_HOST_ASSERT(cached_psum_num_recv_tokens_per_expert.has_value());
741	            EP_HOST_ASSERT(cached_dst_buffer_slot_idx.has_value());
742	
743	            // Hybrid kernels require more
744	            if (nccl_context->num_scaleout_ranks > 1) {
745	                EP_HOST_ASSERT(cached_token_metadata_at_forward.has_value());
746	                EP_HOST_ASSERT(cached_channel_linked_list.has_value());
747	            }
748	        }
749	
750	        // Check data tensor
751	        const auto [num_tokens, hidden] = get_shape<2>(x);
752	        const auto num_hidden_bytes = hidden * static_cast<int>(x.element_size());
753	        const auto num_local_experts = num_experts / nccl_context->num_ranks;
754	        EP_HOST_ASSERT(x.is_cuda() and x.is_contiguous());
755	        EP_HOST_ASSERT((x.size(1) * x.element_size()) % sizeof(int4) == 0);
756	        EP_HOST_ASSERT(num_tokens <= num_max_tokens_per_rank);
757	
758	        // Check SF stuffs
759	        int num_sf_packs = 0;
760	        void* sf_ptr = nullptr;
761	        int sf_token_stride = 0, sf_hidden_stride = 0;
762	        if (sf.has_value()) {
763	            // SF must be FP32 or packed UE8M0x4
764	            const auto [num_tokens_, num_sf_packs_] = get_shape<2>(sf.value());
765	            EP_HOST_ASSERT(num_tokens == num_tokens_);
766	            EP_HOST_ASSERT(sf->is_cuda());
767	            EP_HOST_ASSERT(sf->element_size() == sizeof(sf_pack_t));
768	            num_sf_packs = num_sf_packs_;
769	            sf_ptr = sf->data_ptr();
770	            sf_token_stride = sf->stride(0);
771	            sf_hidden_stride = sf->stride(1);
772	        }
773	
774	        // Check top-k stuffs
775	        const auto [num_tokens_, num_topk] = get_shape<2>(topk_idx);
776	        EP_HOST_ASSERT(num_tokens == num_tokens_);
777	        EP_HOST_ASSERT(topk_idx.scalar_type() == c10::CppTypeToScalarType<topk_idx_t>::value);
778	        EP_HOST_ASSERT(topk_idx.is_cuda() and topk_idx.is_contiguous());
779	
780	        // Weights are optional for training backward
781	        float* topk_weights_ptr = nullptr;
782	        if (topk_weights.has_value()) {
783	            const auto [num_tokens__, num_topk_] = get_shape<2>(topk_weights.value());
784	            EP_HOST_ASSERT(num_tokens == num_tokens__);
785	            EP_HOST_ASSERT(topk_weights->is_cuda() and topk_weights->is_contiguous());
786	            topk_weights_ptr = topk_weights->data_ptr<float>();
787	        }
788	
789	        // Expert receiving counter
790	        int* cumulative_local_expert_recv_stats_ptr = nullptr;
791	        if (cumulative_local_expert_recv_stats.has_value()) {
792	            const auto [num_local_experts_] = get_shape<1>(cumulative_local_expert_recv_stats.value());
793	            EP_HOST_ASSERT(cumulative_local_expert_recv_stats->is_cuda() and
794	                           cumulative_local_expert_recv_stats->is_contiguous());
795	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
796	            cumulative_local_expert_recv_stats_ptr = cumulative_local_expert_recv_stats->data_ptr<int>();
797	        }
798	
799	        // Stream control
800	        // All new tensor allocations should happen after this
801	        const auto compute_stream = stream_control_prologue(previous_event, allocate_on_comm_stream, async_with_compute_stream);
802	
803	        // The number of received tokens per expert
804	        // This is useful for expanding mode
805	        EP_HOST_ASSERT(num_experts % nccl_context->num_ranks == 0);
806	        auto psum_num_recv_tokens_per_expert = cached_psum_num_recv_tokens_per_expert.value_or(torch::Tensor());
807	        if (cached_mode) {
808	            const auto& [num_local_experts_] = get_shape<1>(psum_num_recv_tokens_per_expert);
809	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
810	            EP_HOST_ASSERT(psum_num_recv_tokens_per_expert.is_cuda() and psum_num_recv_tokens_per_expert.is_contiguous());
811	            EP_HOST_ASSERT(psum_num_recv_tokens_per_expert.scalar_type() == torch::kInt);
812	        } else {
813	            // NOTES: for expand mode, the input is exclusive prefix sum, while for non-expand, it is inclusive
814	            psum_num_recv_tokens_per_expert = torch::empty(
815	                {num_local_experts + 1}, at::TensorOptions(torch::kCUDA).dtype(torch::kInt));
816	        }
817	
818	        // The unaligned (actual) number of received tokens per expert
819	        // Written by the dispatch kernel's notify warps, used by the epilogue for zero padding
820	        auto num_unaligned_recv_tokens_per_expert = cached_num_unaligned_recv_tokens_per_expert.value_or(torch::Tensor());
821	        int* num_unaligned_recv_tokens_per_expert_ptr = nullptr;
822	        if (cached_mode) {
823	            const auto& [num_local_experts_] = get_shape<1>(num_unaligned_recv_tokens_per_expert);
824	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
825	            EP_HOST_ASSERT(num_unaligned_recv_tokens_per_expert.is_cuda() and num_unaligned_recv_tokens_per_expert.is_contiguous());
826	            EP_HOST_ASSERT(num_unaligned_recv_tokens_per_expert.scalar_type() == torch::kInt);
827	        } else {
828	            num_unaligned_recv_tokens_per_expert = torch::empty(
829	                {num_local_experts}, at::TensorOptions(torch::kCUDA).dtype(torch::kInt));
830	        }
831	        num_unaligned_recv_tokens_per_expert_ptr = num_unaligned_recv_tokens_per_expert.data_ptr<int>();
832	
833	        // The prefix sum tensor of number of received tokens from each rank
834	        // Will also be used in combine as the dispatch handle
835	        auto psum_num_recv_tokens_per_scaleup_rank = cached_psum_num_recv_tokens_per_scaleup_rank.value_or(torch::Tensor());
836	        if (cached_mode) {
837	            const auto [num_scaleup_ranks] = get_shape<1>(psum_num_recv_tokens_per_scaleup_rank);
838	            EP_HOST_ASSERT(num_scaleup_ranks == nccl_context->num_scaleup_ranks);
839	            EP_HOST_ASSERT(psum_num_recv_tokens_per_scaleup_rank.is_cuda() and psum_num_recv_tokens_per_scaleup_rank.is_contiguous());
840	            EP_HOST_ASSERT(psum_num_recv_tokens_per_scaleup_rank.scalar_type() == torch::kInt);
841	        } else {
842	            psum_num_recv_tokens_per_scaleup_rank = torch::empty(
843	                {nccl_context->num_scaleup_ranks}, at::TensorOptions(torch::kCUDA).dtype(torch::kInt));
844	        }
845	
846	        // Decide number of channels by shared memory consumption
847	        // Only for hybrid version
848	        int num_channels_per_sm = 1, num_channels = 1;
