861	                /* 2 kinds of warps */ num_channels_per_sm / 2, kNumMaxChannelsPerSM);
862	            if (not prefer_overlap_with_compute)
863	                num_channels_per_sm = std::min<int>(num_channels_per_sm, 4);
864	            num_channels = num_sms * num_channels_per_sm;
865	            if (get_env<int>("EP_BUFFER_DEBUG"))
866	                printf("Elastic buffer uses %d channels per SM\n", num_channels_per_sm);
867	        }
868	
869	        // Non-hybrid mode handles
870	        auto dst_buffer_slot_idx = cached_dst_buffer_slot_idx.value_or(torch::Tensor());
871	        if (nccl_context->num_scaleout_ranks == 1) {
872	            if (cached_mode) {
