877	            } else {
878	                // Allocate a new tensor
879	                dst_buffer_slot_idx = torch::empty(
880	                    {num_tokens, num_topk}, torch::TensorOptions(torch::kCUDA).dtype(torch::kInt));
881	            }
882	        }
883	
884	        // Hybrid mode handles
885	        std::optional<torch::Tensor> token_metadata_at_forward, channel_linked_list;
