924	                token_metadata_at_forward = torch::empty(
925	                    {num_channels, num_max_forwarded_tokens, num_forward_metadata_dims},
926	                    torch::TensorOptions().device(torch::kCUDA).dtype(torch::kInt)
927	                );
928	            }
929	            token_metadata_at_forward_ptr = token_metadata_at_forward->data_ptr<int>();
930	
931	            // Per-scaleup-peer-per-channel linked list
932	            // `[i, j, k]` means: from channel i from scaleup peer k, the j-th token's index in the combine's input
933	            if (cached_mode) {
934	                channel_linked_list = cached_channel_linked_list;
935	                const auto [num_channels__, d1_, d2_] = get_shape<3>(channel_linked_list.value());
