1038	                        num_recv_tokens_per_expert_list.push_back(count);
1039	                        num_expanded_tokens += count;
1040	                        ++ counter_local_expert_idx;
1041	                    }
1042	                }
1043	
1044	                // Ready and do next steps
1045	                const auto get_buffer_info = [&]() {
1046	                    std::stringstream ss;
1047	                    ss << "CPU side received count (scaleup: " << nccl_context->scaleup_rank_idx << "): ";
1048	                    for (int i = 0; i < nccl_context->num_scaleup_ranks + num_local_experts; ++ i) {
